    "team.desc": "\u0641\u0631\u064a\u0642 \u0634\u063a\u0648\u0641 \u0645\u0646 \u0631\u0648\u0627\u0629 \u0627\u0644\u0642\u0635\u0635 \u0627\u0644\u0628\u0635\u0631\u064a\u0629 \u0645\u0643\u0631\u0633 \u0644\u0627\u0644\u062a\u0642\u0627\u0637 \u0623\u0641\u0636\u0644 \u0644\u062d\u0638\u0627\u062a\u0643\u0645.",
